        return new Source("{% extends 'base.html.twig' %}

{% block title %}Review index{% endblock %}

{% block body %}


    <h1>Review index</h1>

    <table class=\"table\">
        <thead>
            <tr>
                <th>Id</th>
                <th>Title</th>
                <th>Author</th>
                <th>Pages</th>
                <th>Summary</th>
                <th>Genre</th>
                <th>Reviewer</th>
                <th>Text</th>
                <th>actions</th>
            </tr>
        </thead>
        <tbody>
        {% for review in reviews %}
            <tr>
                <td>{{ review.id }}</td>
                <td>{{ review.book.title }}</td>
                <td>{{ review.book.author }}</td>
                <td>{{ review.book.pages }}</td>
                <td>{{ review.book.summary }}</td>
                <td>{{ review.book.genre }}</td>
                <td>{{ review.reviewer.email }}</td>
                <td>{{ review.reviewText }}</td>
                <td>
                    <a href=\"{{ path('app_review_show', {'id': review.id}) }}\">show</a>
                    <a href=\"{{ path('app_review_edit', {'id': review.id}) }}\">edit</a>
                </td>
            </tr>
        {% else %}
            <tr>
                <td colspan=\"9\">no records found</td>
            </tr>
        {% endfor %}
        </tbody>
    </table>
{% endblock %}
